def normalize_station_code(code: str) -> str:
    return code.strip().upper()

def build_code_map():
    code_to_index = {}
    code_to_name = {}
    for idx, station in enumerate(STATIONS):
        for code in station["codes"]:
            code_to_index[code] = idx
            code_to_name[code] = station["name"]
    return code_to_index, code_to_name

CODE_TO_INDEX, CODE_TO_NAME = build_code_map()

def get_fare(code1: str, code2: str) -> int:
    c1 = normalize_station_code(code1)
    c2 = normalize_station_code(code2)

    if c1 not in CODE_TO_INDEX:
        raise ValueError(f"找不到站號: {c1}")
    if c2 not in CODE_TO_INDEX:
        raise ValueError(f"找不到站號: {c2}")

    i = CODE_TO_INDEX[c1]
    j = CODE_TO_INDEX[c2]

    if i == j:
        return 0

    if i > j:
        i, j = j, i

    return STATIONS[j]["fares"][i]

def get_station_name(code: str) -> str:
    c = normalize_station_code(code)
    if c not in CODE_TO_NAME:
        raise ValueError(f"找不到站號: {c}")
    return CODE_TO_NAME[c]

def main():
    user_input = input("請輸入兩個站號（例如：G11 O03）: ").strip()
    parts = user_input.split()

    if len(parts) != 2:
        print("格式錯誤，請輸入兩個站號，例如：G11 O03")
        return

    code1, code2 = map(normalize_station_code, parts)

    try:
        fare = get_fare(code1, code2)
        name1 = get_station_name(code1)
        name2 = get_station_name(code2)
        print(f"{code1} {name1} -> {code2} {name2} 的票價是 {fare} 元")
    except ValueError as e:
        print(e)

if __name__ == "__main__":
    main()
